async (command: T, context?: AsyncContext) => {
  context ??= AsyncContext.of(command) ?? new AsyncContext();

  if (!AsyncContext.isAttached(context)) {
    // Commands returned by sagas may already have an async context set
    // and a corresponding request provider registered.
    this.moduleRef.registerRequestByContextId(context, context.id);

    context.attachTo(command);
  }

  const instance = await this.moduleRef.resolve(
    handler.metatype!,
    context.id,
    {
      strict: false,
    },
  );
  return instance.execute(command as T & Command<unknown>);
}

export function normalizeResolverArgs(args: any[]) {
  // Reference resolver args don't have args argument (3 args instead of 4)
  const isReferenceResolver = args.length === 3;
  // Resolve type args don't have args argument and the last argument is the parent object type
  const isResolveType = !isReferenceResolver && isType(args[args.length - 1]);

  // Only create a new array when we need to insert undefined at position 1
  // This avoids array allocation for the common 4-argument case
  if (isReferenceResolver || isResolveType) {
    // Insert undefined at position 1: [root, ctx, info] -> [root, undefined, ctx, info]
    return [args[0], undefined, args[1], args[2], args[3]];
  }

  // Return original array for the common case (no mutation needed)
  return args;
}

public getGuardInstance(
  metatype: Function | CanActivate,
  contextId = STATIC_CONTEXT,
  inquirerId?: string,
): CanActivate | null {
  const isObject = !!(metatype as CanActivate).canActivate;
  if (isObject) {
    return metatype as CanActivate;
  }
  const instanceWrapper = this.getInstanceByMetatype(
    metatype as Type<unknown>,
  );
  if (!instanceWrapper) {
    return null;
  }
  const instanceHost = instanceWrapper.getInstanceByContextId(
    this.getContextId(contextId, instanceWrapper),
    inquirerId,
  );
  return instanceHost && instanceHost.instance;
}

