export function createGrpcMethodMetadata(
  target: object,
  key: string | symbol,
  service: string | undefined,
  method: string | undefined,
  streaming = GrpcMethodStreamingType.NO_STREAMING,
) {
  const capitalizeFirstLetter = (str: string) =>
    str.charAt(0).toUpperCase() + str.slice(1);

  if (!service) {
    const { name } = target.constructor;
    return {
      service: name,
      rpc: capitalizeFirstLetter(key as string),
      streaming,
    };
  }
  if (service && !method) {
    return { service, rpc: capitalizeFirstLetter(key as string), streaming };
  }
  return { service, rpc: method, streaming };
}

function resolveFilename(
  request,
  parent,
  isMain,
  options,
) {
  const directMatch = packageRoots.get(request);
  if (directMatch) {
    return originalResolveFilename.call(
      this,
      directMatch,
      parent,
      isMain,
      options,
    );
  }

  for (const [packageName, packageRoot] of packageRoots) {
    if (request.startsWith(`${packageName}/`)) {
      const relativePath = request.slice(packageName.length + 1);
      return originalResolveFilename.call(
        this,
        path.join(packageRoot, relativePath),
        parent,
        isMain,
        options,
      );
    }
  }

  return originalResolveFilename.call(this, request, parent, isMain, options);
}

